import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureAdminSiteStrings } from './config';
import { insureAdminSiteActions } from './actions';
import { MyPopupMenu, ArticleEditableCard, MyDialog, breadCrumbActions } from '../../includes';
import { drawerWidth } from '../../includes/Header/Drawer';
import { ContentControl } from './ContentControl';
import { Button } from '@material-ui/core';
import { insureAdminUtilStrings } from '../utils';
import { NewArticle } from '../../includes/ArticleComponents/NewArticle';
import { store } from '../../../helpers';
import { Delete } from '@material-ui/icons';
import { appActions, alertAction } from '../../../actions';
import { insureAdminRouteNames } from '../routeNames';


const style = theme => ({
    root: {
        position: "relative",
    },
    menu : {
        [theme.breakpoints.up("sm")] : {
            width : "calc(100% - "+(drawerWidth+50)+"px)",
        },
        [theme.breakpoints.down("xs")] :{
            width : "100%"
        }
    }
})
class _Site extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        this.state = {
            option : null,
            articleEditing : false,
            newArticleDialog : false,
            siteInfo : null,
        }
        breadCrumbActions.setBreadCrumb([
            {name : "Site", path : insureAdminRouteNames.home}
        ])(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [insureAdminSiteStrings.siteInfo] : siteInfo
        } = props;
        if(state.option && JSON.stringify(state.siteInfo) !== JSON.stringify(siteInfo)){
            const {item : optionItem} = siteInfo.getFirstObjectByPropValue("name", state.option.name);
            state.option = optionItem;
        }
        return state;
    }
    componentDidMount() {
        const {
            dispatch,
            [insureAdminSiteStrings.siteInfo] : siteInfo,
        } = this.props;
        if(!siteInfo) insureAdminSiteActions.getSiteInfo()(dispatch);
    }
    onCreateClick = name => form => {
        form.append("name", name);
        const {dispatch} = this.props;
        insureAdminSiteActions.postNewArticle(form, done=>{
            this.setState({newArticleDialog : false})
        })(dispatch);
    }
    updateArticle = (property, name, subname) => (value, context) => {
        const {dispatch} = this.props;
        if(property === "src"){
            const form = new FormData();
            form.append("articleImage", value);
            form.append("oldPath", context);
            form.append("name", name);
            form.append("subname", subname);
            form.append("property", property);
            insureAdminSiteActions.updateArticle(property, name, subname, form)(dispatch);
        }else{
            insureAdminSiteActions.updateArticle(property, name, subname, {value}, done=>{
                context.setState({loading : false, editing : false});
            })(dispatch);
        }

    }
    deleteArticle = (name, subname) => () => {
        const {dispatch} = this.props;
        const self = this;
        appActions.showSnackDialog(
            "Are you sure you want to delete this " + name,
            <Button key="continueBtn" variant="contianed" color="secondary" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                insureAdminSiteActions.deleteArticle(name, subname, done=>{
                    if(done) self.setState({articleEditing : false})
                })(dispatch);
            }}>Contiue</Button>
        )(dispatch);
    }
    notificationHandler(message, type){
        const {dispatch } = this.props;
        appActions.showSnackbar(
            alertAction[type](message)
        )(dispatch);
    }
    render() {
        const {
            classes,
            [insureAdminSiteStrings.siteInfo] : siteInfo,
            [insureAdminUtilStrings.backendBaseUrl] : baseUrl,
            [insureAdminUtilStrings.defaultImage] : defaultImage,
        } = this.props;
        const {option, articleEditing, articleOption, newArticleDialog} = this.state;
        return (
            <div className={classes.root}>
                <MyDialog open={newArticleDialog}>
                    <NewArticle
                        profilePictureProps={{
                            src : defaultImage,
                            baseUrl
                        }}
                        notify={this.notificationHandler.bind(this)}
                        cancelBtnClick={()=>this.setState({newArticleDialog : false})}
                        onCreateClick={this.onCreateClick(option && option.name)}/>
                </MyDialog>
                <MyPopupMenu
                    classes={{
                        menu : classes.menu
                    }}
                    buttonName="site_headers"
                    buttonValue="Select Site Category"
                    options={siteInfo}
                    optionNameProp="header"
                    optionValueProp="_id"
                    menuProps={{
                        anchorOrigin :{
                            horizontal : "left",
                            vertical : "top",
                        },
                        anchorPosition:{
                            top : 0,
                            left : 100,
                        }
                    }}
                    optionClickCallback={option=>this.setState({option})}/>
                {option && 
                    (articleEditing ? 
                        <div style={{
                            display : "flex",
                            flexDirection : "column"
                        }}>
                            <div style={{margin : "10px 0px"}}><Button 
                                variant="contained" 
                                color="secondary"
                                onClick={()=>this.setState({articleEditing : false})}>
                                Back
                            </Button></div>
                            <div style={{margin : "10px 0px"}}><Button
                                variant="contained"
                                color="secondary"
                                onClick={this.deleteArticle(option.name, articleOption.name)}>
                                    <Delete/>Delete
                                </Button></div>
                            <ArticleEditableCard 
                                baseUrl={baseUrl}
                                {...articleOption}
                                uploadImage={this.updateArticle("src", option.name, articleOption.name)}
                                updateContent={this.updateArticle("body", option.name, articleOption.name)}
                                updateHeader={this.updateArticle("header", option.name, articleOption.name)}
                                /> 
                        </div>: 
                        (option.value ? 
                            <ContentControl {...option}/> : 
                            <div>
                                {option.name === "blogs" || option.name === "services" || option.name === "carousel" ?
                                    <Button 
                                        variant="contained" 
                                        color="primary"
                                        onClick={()=>this.setState({newArticleDialog : true})}>
                                        New
                                    </Button> : null
                                }
                                {option.values && option.values.map((item, index)=>{
                                    return <ContentControl 
                                        articleEditHandler={articleOption=>this.setState({articleOption, articleEditing : true})}
                                        option={option} 
                                        key={index} 
                                        {...item}/>
                                })}
                            </div>
                        )
                    )}
            </div>
        );
    }
}


_Site.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({insureAdminSiteReducer, insureAdminUtilReducer}) => ({
    [insureAdminSiteStrings.siteInfo] : insureAdminSiteReducer[insureAdminSiteStrings.siteInfo],
    [insureAdminUtilStrings.backendBaseUrl] : insureAdminUtilReducer[insureAdminUtilStrings.backendBaseUrl],
    [insureAdminUtilStrings.defaultImage] : insureAdminUtilReducer[insureAdminUtilStrings.defaultImage],
})


export const Site = connect(mapStateToProps)(withStyles(style)(_Site));
export {Site as default}