import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextField } from '@material-ui/core';
import { TextFieldEditableCard } from '../../../../includes';
const style = theme => ({
    root: {
        
    },
    textField : {

    }
})
class _FormDataEditor extends Component {
    updateName = name => (value, context) => {
        const {onUpdateClick} = this.props;
        if(onUpdateClick) onUpdateClick(value, context, name);
    }
    render() {
        const {classes, data, nameMap} = this.props;
        if(this.props.textFieldEditableCardProps && 
            this.props.textFieldEditableCardProps.onUpdateClick) 
            throw("onUpdateClick is not allowed here, use updateValue(name, value) instead")
        return (
            <div className={classes.root}>
                {data && Object.entries(data).map((item, index)=>{
                    const name = nameMap ? nameMap(item[0]) : item[0];
                    const value = item[1];
                    return <TextFieldEditableCard
                        key={index}
                        header={name}
                        value={value}
                        {...this.props.textFieldEditableCardProps}
                        onUpdateClick={this.updateName(item[0])}/>
                })}
            </div>
        );
    }
}
_FormDataEditor.propTypes = {
    classes : PropTypes.object.isRequired,
    data : PropTypes.object,
    updateValue : PropTypes.func,
    nameMap : PropTypes.func,
    textFieldEditableCardProps : PropTypes.shape(
        TextFieldEditableCard.propTypes
    ), 
    onUpdateClick:PropTypes.func,
};
export const FormDataEditor = withStyles(style)(_FormDataEditor);